INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('b3cd2c5d-9b91-464d-a5ae-c99b23b7795f', 'first_person_claims', true, 'warning', '{"max_penalty": 3.0, "penalty_per": 1.0}', NULL, 'Penalises ''I/we built/created/...'' phrasing in the post body. Bypassed for niches in `qa_allow_first_person_niches` (CSV) for backwards compatibility with PR #160. Tune `applies_to_niches` to scope this rule to specific niches.', '2026-05-02 15:01:49.23912+00', '2026-05-02 15:01:49.23912+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('c6fccec1-f6be-4313-8c63-0b67406fa955', 'meta_commentary', true, 'warning', '{"max_penalty": 2.0, "penalty_per": 0.5}', NULL, 'Penalises ''in this post'', ''we''ll explore'', ''this article discusses'' and similar self-referential phrasing in the body.', '2026-05-02 15:01:49.241123+00', '2026-05-02 15:01:49.241123+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('908ce4b7-59d6-4774-ae1c-4c71edc75562', 'fake_person', true, 'error', '{}', NULL, 'Detects fabricated person names + titles (''Sarah Smith, CEO at ...''). Critical — fabricated humans are a publishing-blocker fail.', '2026-05-02 15:01:49.242165+00', '2026-05-02 15:01:49.242165+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('28f12989-aaa7-4fc2-86d9-c854291c6470', 'fake_stat', true, 'error', '{}', NULL, 'Detects fabricated statistics (''43% reduction'', ''McKinsey study found ...'') without citation backing. Critical fail per Matt 2026-04-11.', '2026-05-02 15:01:49.243144+00', '2026-05-02 15:01:49.243144+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('073ec17a-37eb-4145-a534-b9a4de8e9cfc', 'glad_labs_claim', true, 'error', '{}', NULL, 'Detects impossible claims about the company (decade-long history, thousands of employees, named clients) — uses configured `company_name` + `company_age_months` settings.', '2026-05-02 15:01:49.244106+00', '2026-05-02 15:01:49.244106+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('c6a0a23f-282f-4ced-a695-2b65bcc8401c', 'fake_quote', true, 'error', '{}', NULL, 'Detects fabricated quotes attributed to named people. Critical fail — same class of lie as fake stats.', '2026-05-02 15:01:49.245099+00', '2026-05-02 15:01:49.245099+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('32eaaba6-e4d0-49bc-af1f-a85a9ff97f83', 'fabricated_experience', true, 'error', '{}', NULL, 'Detects AI pretending to be a person (''I was on a call with ...'', ''a client of mine ...''). Critical fail.', '2026-05-02 15:01:49.246084+00', '2026-05-02 15:01:49.246084+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('c33a1d4a-8596-4f1b-8630-825233d59e09', 'hallucinated_link', true, 'error', '{}', NULL, 'Detects ''see our guide on X'' phrasing that points at internal content that doesn''t exist. Critical fail.', '2026-05-02 15:01:49.247074+00', '2026-05-02 15:01:49.247074+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('2493522b-5fa7-4015-a193-b4140dd7d2c5', 'unlinked_citation', true, 'warning', '{"warning_reject_threshold": 3}', NULL, 'Detects ''introduced in <Paper Title>'', ''according to <Source>'', ''arXiv:2401.12345'' without an accompanying URL. Promoted to critical when the matched text names a source type (Medium, article, paper, study) without a URL within ~100 chars.', '2026-05-02 15:01:49.248091+00', '2026-05-02 15:01:49.248091+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('ddc2c1f7-ba60-4585-bc50-7df5e7f2c82c', 'hallucinated_reference', true, 'warning', '{}', NULL, 'Detects backtick-quoted library/API references that don''t match Python stdlib, top-500 PyPI, or known Ollama models. Also flags topic-orthogonal library mentions (CadQuery in an ai-ml post).', '2026-05-02 15:01:49.249117+00', '2026-05-02 15:01:49.249117+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('e3cb5109-9785-4959-aa59-3978299d8fc6', 'code_block_density', true, 'warning', '{"min_line_ratio_pct": 20, "min_blocks_per_700w": 1, "long_post_floor_words": 300}', NULL, 'Warns when tech-tagged posts ship without enough fenced code blocks. Tag list comes from `code_density_tag_filter`. Soft signal — never critical. Disabled via `code_density_check_enabled` OR by setting this row''s `enabled=false`.', '2026-05-02 15:01:49.250156+00', '2026-05-02 15:01:49.250156+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('afad17ad-456b-4fa4-9391-ae3fda264ef5', 'brand_contradiction', true, 'warning', '{}', NULL, 'Detects content promoting paid cloud APIs (''OpenAI pricing'', ''pay per token to Anthropic''). Brand-specific to local-first Ollama positioning.', '2026-05-02 15:01:49.251227+00', '2026-05-02 15:01:49.251227+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('17ac0be6-ca77-4eec-a612-bebc668e4b72', 'leaked_image_prompt', true, 'warning', '{}', NULL, 'Detects image-generation prompts left inline in the markdown after image rendering (''*A split-screen comparison of ...*'').', '2026-05-02 15:01:49.252177+00', '2026-05-02 15:01:49.252177+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('e4fcee03-1b6f-4145-a836-8b989a136aaa', 'image_placeholder', true, 'error', '{}', NULL, 'Detects [IMAGE-1: ...], [FIGURE: ...], [DIAGRAM: ...] placeholder tokens that the image pipeline failed to replace. Critical — these leak into the rendered post and look broken.', '2026-05-02 15:01:49.253213+00', '2026-05-02 15:01:49.253213+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('55c9934e-5201-4780-9633-73946f816a45', 'known_wrong_fact', true, 'error', '{}', NULL, 'Detects facts overridden via the `fact_overrides` DB table. Severity is set per-row in fact_overrides, but this rule must be enabled for the override gate to fire at all.', '2026-05-02 15:01:49.254217+00', '2026-05-02 15:01:49.254217+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('fa73db81-67c3-48b1-a78d-7a11a2ecdca0', 'filler_phrase', true, 'warning', '{}', NULL, 'Detects LLM filler phrases (''many organizations have found'', ''the landscape is constantly evolving'', ''in today''s fast-paced world''). Score-penalty only.', '2026-05-02 15:01:49.255226+00', '2026-05-02 15:01:49.255226+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('cbab4145-8559-4168-b996-6250b1ecaf3d', 'filler_intro', true, 'warning', '{}', NULL, 'Detects ''In this post/article/guide/tutorial'' opening lines in the first 500 chars. Score-penalty only.', '2026-05-02 15:01:49.256238+00', '2026-05-02 15:01:49.256238+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('6cf4f7ff-955b-42ae-b72d-8a800e739cdf', 'banned_header', true, 'warning', '{}', NULL, 'Detects generic section headings (''## Introduction'', ''## Conclusion'', ''## Summary'', etc.). Score-penalty only.', '2026-05-02 15:01:49.257228+00', '2026-05-02 15:01:49.257228+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('84442c57-56ff-48da-9e51-c4085b5465ca', 'late_acronym_expansion', true, 'warning', '{"min_prior_uses": 2}', NULL, 'Detects acronyms expanded after they''ve already been used 2+ times unexpanded (''use the CRM ... CRM (Customer Relationship Management)'').', '2026-05-02 15:01:49.258204+00', '2026-05-02 15:01:49.258204+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('42f43432-3261-4656-95b2-22fe78c7aece', 'truncated_content', true, 'error', '{}', NULL, 'Detects content that ends mid-sentence — strong signal the LLM hit its output token limit. Critical — readers get an incomplete article.', '2026-05-02 15:01:49.259161+00', '2026-05-02 15:01:49.259161+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('250e1868-699a-4db4-b96a-2a4a990106e2', 'title_diversity', true, 'warning', '{}', NULL, 'Detects titles starting with overused openers (''Beyond the ...'', ''Unlocking ...'', ''The Ultimate Guide to ...''). Score-penalty only.', '2026-05-02 15:01:49.260129+00', '2026-05-02 15:01:49.260129+00') ON CONFLICT DO NOTHING;
INSERT INTO public.content_validator_rules (id, name, enabled, severity, threshold, applies_to_niches, description, created_at, updated_at) VALUES ('4d918005-fd67-4a4a-850a-11632618ab53', 'title_year_claim', true, 'error', '{}', NULL, 'Detects titles claiming multi-year history (''Five Years of ...'', ''10 Years Building ...'') that contradict configured `company_age_months`.', '2026-05-02 15:01:49.261092+00', '2026-05-02 15:01:49.261092+00') ON CONFLICT DO NOTHING;
INSERT INTO public.qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata, last_run_at, last_run_duration_ms, last_run_status, total_runs, total_rejections, last_error, created_at, updated_at) VALUES ('c7bde483-660e-4c2f-9188-f4b29dd066e5', 'programmatic_validator', 'qa', 100, 'programmatic_validator', true, true, '{}', '{"description": "Anti-hallucination regex + heuristic checks. Catches fabricated people, fake stats, invented quotes. Always-on safety net.", "legacy_setting_key": null, "seeded_by_migration": "0094", "legacy_setting_value_at_seed": null}', NULL, NULL, NULL, 0, 0, NULL, '2026-04-27 06:06:10.352858+00', '2026-04-27 06:06:10.352858+00') ON CONFLICT DO NOTHING;
INSERT INTO public.qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata, last_run_at, last_run_duration_ms, last_run_status, total_runs, total_rejections, last_error, created_at, updated_at) VALUES ('551643c0-65c8-4ddf-83c5-6ad5d02e6a60', 'llm_critic', 'qa', 200, 'llm_critic', true, true, '{}', '{"description": "Cross-model review by a different LLM than the writer. Style, logic, coherence, suspiciously specific claims.", "legacy_setting_key": null, "seeded_by_migration": "0094", "legacy_setting_value_at_seed": null}', NULL, NULL, NULL, 0, 0, NULL, '2026-04-27 06:06:10.355028+00', '2026-04-27 06:06:10.355028+00') ON CONFLICT DO NOTHING;
INSERT INTO public.qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata, last_run_at, last_run_duration_ms, last_run_status, total_runs, total_rejections, last_error, created_at, updated_at) VALUES ('a3c12978-bf9c-493f-9f03-0d2a3454846d', 'url_verifier', 'qa', 300, 'url_verifier', true, true, '{}', '{"description": "HEAD-checks every external URL in the content. Dead links block publish; healthy citations earn a small score bonus.", "legacy_setting_key": null, "seeded_by_migration": "0094", "legacy_setting_value_at_seed": null}', NULL, NULL, NULL, 0, 0, NULL, '2026-04-27 06:06:10.357227+00', '2026-04-27 06:06:10.357227+00') ON CONFLICT DO NOTHING;
INSERT INTO public.qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata, last_run_at, last_run_duration_ms, last_run_status, total_runs, total_rejections, last_error, created_at, updated_at) VALUES ('4b39682e-c724-4556-96b7-cf38908000b7', 'consistency', 'qa', 400, 'consistency', false, true, '{}', '{"description": "Internal-consistency gate — catches sections that contradict each other. Advisory unless score is unambiguously low.", "legacy_setting_key": null, "seeded_by_migration": "0094", "legacy_setting_value_at_seed": null}', NULL, NULL, NULL, 0, 0, NULL, '2026-04-27 06:06:10.359356+00', '2026-04-27 06:06:10.359356+00') ON CONFLICT DO NOTHING;
INSERT INTO public.qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata, last_run_at, last_run_duration_ms, last_run_status, total_runs, total_rejections, last_error, created_at, updated_at) VALUES ('de37b591-6a63-430e-b94d-988fcc82272b', 'web_factcheck', 'qa', 500, 'web_factcheck', false, true, '{}', '{"description": "DuckDuckGo lookup for product/spec claims that the LLM critic cannot verify (training-cutoff override). Advisory.", "legacy_setting_key": "qa_web_factcheck_enabled", "seeded_by_migration": "0094", "legacy_setting_value_at_seed": null}', NULL, NULL, NULL, 0, 0, NULL, '2026-04-27 06:06:10.361543+00', '2026-04-27 06:06:10.361543+00') ON CONFLICT DO NOTHING;
INSERT INTO public.qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata, last_run_at, last_run_duration_ms, last_run_status, total_runs, total_rejections, last_error, created_at, updated_at) VALUES ('81df452a-c368-4592-bd10-9c533ed08246', 'vision_gate', 'qa', 600, 'vision_gate', false, true, '{}', '{"description": "Vision-model inline-image relevance check. Catches the ''stock photo of a server room on a FastAPI post'' pattern.", "legacy_setting_key": "qa_vision_check_enabled", "seeded_by_migration": "0094", "legacy_setting_value_at_seed": "true"}', NULL, NULL, NULL, 0, 0, NULL, '2026-04-27 06:06:10.363648+00', '2026-04-27 06:06:10.363648+00') ON CONFLICT DO NOTHING;
INSERT INTO public.qa_gates (id, name, stage_name, execution_order, reviewer, required_to_pass, enabled, config, metadata, last_run_at, last_run_duration_ms, last_run_status, total_runs, total_rejections, last_error, created_at, updated_at) VALUES ('714d51a3-cbc6-4664-affa-b2570344a623', 'deepeval_brand_fabrication', 'qa', 700, 'deepeval_brand_fabrication', false, true, '{}', '{"epic": "glad-labs-stack#329", "scaffold": "services/deepeval_rails.py", "description": "DeepEval BrandFabricationMetric — wraps content_validator fabrication patterns as a DeepEval BaseMetric. Advisory.", "seeded_by_migration": "20260508_215727"}', NULL, NULL, NULL, 0, 0, NULL, '2026-05-09 00:42:23.175884+00', '2026-05-09 00:42:23.175884+00') ON CONFLICT DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('active_pipeline_experiment_key', '', 'experiments', 'Experiment key the content pipeline routes through (matches experiments.key in the experiments table). Empty = disabled. Set via `poindexter settings set active_pipeline_experiment_key <key>` to opt the pipeline into an A/B experiment. The harness is best-effort — a misconfigured experiment never halts the pipeline, just falls back to default config.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('alert_dedup_state_retention_hours', '168', 'alerts', 'Retention horizon for alert_dedup_state rows. The retention janitor deletes rows whose last_seen_at aged past this many hours so the table doesn''t grow unbounded as fingerprints churn over time. Default 168 = 7 days. Glad-Labs/poindexter#420.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('alert_force_telegram_event_types', '', 'alerts', 'Comma-separated list of event_type (or alertname) values that always route to Telegram regardless of severity. Use for alerts like ''cost_guard_tripped,worker_crashed_unrecoverable'' that the operator wants on their phone even at warning severity. Empty default = no overrides; pure severity routing applies (critical/error -> both, warning/info -> Discord only). Glad-Labs/poindexter#420.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('alert_repeat_summarize_threshold_minutes', '30', 'alerts', 'After a fingerprint has been firing continuously for this many minutes (now - first_seen_at), the dispatcher escalates to an AI summary that counts repeats, lists time-correlated other alerts in the same window, and produces a paragraph diagnosis. One-shot per fingerprint (marked via summary_dispatched_at). Default 30 min. Glad-Labs/poindexter#420.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('alert_repeat_suppress_window_minutes', '30', 'alerts', 'When a brain alert with the same fingerprint (source|severity|normalized_message) last fired inside this window, the new fire is counted (repeat_count++) but NOT dispatched. Default 30 = the same alert at most every 30 min until escalation. Set to 0 to disable dedup entirely (every fire dispatches). Glad-Labs/poindexter#420.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('allowed_origins', 'https://gladlabs.io,https://www.gladlabs.io', 'cors', 'Comma-separated allowed CORS origins', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('alt_text_budget', '120', 'content', 'Character budget for inline <img alt="..."> text. The alt generator produces complete sentences within this budget; over-budget drafts are re-summarised or fall back to a topic-based template — never mid-word truncated. Ref: GH-84.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('api_base_url', 'http://worker:8002', 'identity', 'Backend API base URL', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('api_url', 'http://localhost:8002', 'general', 'Backend API base URL (legacy alias for api_base_url)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_gate_draft_enabled', 'true', 'general', 'Whether the draft gate is enabled by default.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_gate_final_enabled', 'true', 'general', 'Whether the final pre-distribution gate is enabled by default.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_gate_media_generation_failed_enabled', 'true', 'general', 'Whether the auto-escalation gate fires when per-medium generation hits the retry limit.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_gate_podcast_enabled', 'true', 'general', 'Whether the podcast gate is enabled by default.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_gate_short_enabled', 'true', 'general', 'Whether the short-video gate is enabled by default.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_gate_topic_decision_reject_status', 'dismissed', 'general', 'Status set on pipeline_tasks when a topic-decision gate rejects the topic (vs. the global default ''rejected''). Distinct so dashboards can separate rejected drafts from dismissed topics.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_gate_topic_enabled', 'true', 'general', 'Whether the topic gate is enabled by default. Legacy-style feature flag kept for parity with the existing approval_gate_<name>_enabled UX (poindexter gates set ...).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_gate_video_enabled', 'true', 'general', 'Whether the video gate is enabled by default.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_queue_alert_threshold', '15', 'monitoring', 'Awaiting-approval task count above which the brain `approval_queue` probe alerts. Default 15. Was hardcoded to 5; raised because the throttle gate caps the queue around max_approval_queue (20) — a static 5 just fires constantly during normal pacing.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('approval_ttl_days', '7', 'pipeline', 'Days before unapproved posts are auto-expired', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('app_version', '3.0.1', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('audio_gen_engine', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('auto_append_sources_section', 'true', 'content', 'Auto-append ## Sources at finalize if missing', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('auto_publish_threshold', '0', 'pipeline', 'Quality score threshold for auto-publishing (0=disabled)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_daily_enabled', 'true', 'backup', 'When false, the backup-daily container takes no dumps.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_daily_interval', '24h', 'backup', 'Cadence between daily dumps.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_daily_retention', '7', 'backup', 'Number of daily dumps to keep.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_hourly_enabled', 'true', 'backup', 'When false, the backup-hourly container takes no dumps. Loop keeps running so toggling back on is instant.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_hourly_interval', '1h', 'backup', 'Cadence between hourly dumps. Format: <N>{s|m|h|d}. Read fresh each tick — no restart needed.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_hourly_retention', '24', 'backup', 'Number of hourly dumps to keep. Older dumps are pruned after each successful run.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_backup_dir', '/host-backups/auto', 'backup', 'Host path the backup containers bind-mount their dumps into. Override when POINDEXTER_BACKUP_DIR points somewhere non-default (e.g. a second drive).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_daily_max_age_hours', '26', 'backup', 'Daily tier staleness threshold (mirrors the compose healthcheck slack of 90 min beyond the 24 h cadence).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_enabled', 'true', 'backup', 'Master switch for the brain backup-watcher probe (#388). When false, the probe short-circuits without stat-ing dumps or restarting containers.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_hourly_max_age_minutes', '90', 'backup', 'Hourly tier staleness threshold. Matches the compose healthcheck so the watcher fires at the same instant the container is marked unhealthy.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_max_retries', '2', 'backup', 'Consecutive `docker restart` attempts before the watcher gives up and lets the dispatcher page the operator. Cumulative across cycles.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_poll_interval_minutes', '5', 'backup', 'Cadence at which the watcher re-checks backup freshness. Matches the brain cycle by default; bump higher only if the brain is overloaded.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('backup_watcher_retry_delay_seconds', '120', 'backup', 'How long the watcher waits after `docker restart` before re-stat-ing the dump directory. Long enough for postgres reconnect + initial pg_dump to complete on Matt''s machine.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('brain_anomaly_baseline_window_days', '30', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('brain_anomaly_current_window_hours', '24', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('brain_auto_cancel_grace_minutes', '10', 'pipeline', 'Extra grace period the brain daemon adds on top of stale_task_timeout_minutes before flipping a stuck task to failed. Second line of defence against missed heartbeats during long single-shot GPU calls. Ref: GH-90.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('brand_keywords', '', 'general', 'Comma-separated brand-relevance keywords used by topic_discovery to filter discovered topics to the site''s niche. Empty value falls back to the hardcoded Glad Labs niche set (AI / PC hardware / gaming) for backwards compatibility. Customers running Poindexter for a different niche (e.g. gardening, dentistry) should set this to their own comma-separated list of niche keywords — single-word entries are matched at word boundaries, multi-word / hyphenated entries match as substrings. Case-insensitive. Example: ''gardening,compost,heirloom tomato''.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cli_post_approve_bulk_max_count', '100', 'cli', 'Hard ceiling for matched-post count in a single ''poindexter post approve --no-dry-run --filter ...'' invocation. Refuses to execute when the filter matches more than this many posts unless the operator passes --max=N (still subject to this ceiling). Tighten in production; loosen for backfills.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cli_post_approve_bulk_require_confirm', 'true', 'cli', 'When true, ''poindexter post approve --filter ... --no-dry-run'' always prompts y/N before approving — even if --yes was passed. Belt-and-suspenders for the no-bulk-publish rule. Flip to false only for fully scripted environments where the call site has its own approval gate.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cli_post_create_idempotency_enabled', 'true', 'cli', 'Master switch for `poindexter post create` idempotency (#338). When ''true'', a second invocation with the same computed key inside the window returns the existing post id instead of inserting a duplicate. Set ''false'' to restore the legacy ''every invocation inserts'' behavior.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cli_post_create_idempotency_strategy', 'slug_or_content_hash', 'cli', 'Reserved for future variants of the `poindexter post create` (#338) idempotency-key derivation. Today only ''slug_or_content_hash'' is implemented (slug if explicit, else sha256 of topic+media+gates+operator). Listed here so the knob exists in app_settings before the next strategy lands.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cli_post_create_idempotency_window_minutes', '30', 'cli', 'Dedup window for `poindexter post create` (#338). A second invocation with the same idempotency key WITHIN this many minutes returns the existing post id. Outside the window the command creates a fresh post — protects fat-finger doubles while still allowing a legitimate re-creation of the same topic days later.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cloud_api_daily_limit', '5', 'models', 'Max cloud API calls per day in emergency mode (hard cap)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cloud_api_mode', 'emergency_only', 'models', 'Cloud API usage mode: disabled, emergency_only, fallback, always', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cloud_api_notify_on_use', 'true', 'models', 'Send Telegram alert when a cloud API is used', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cloudflare_account_id', '01ddb679184ebe59cc7f03f8171d76ee', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cloudinary_cloud_name', 'dujk7kdhd', 'integration', 'Cloudinary cloud name', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('code_density_check_enabled', 'true', 'content', 'GH-234: enable the code-block density quality gate. When true, tech-tagged posts that ship without enough fenced code blocks emit a (non-blocking) warning during multi_model_qa review.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('code_density_long_post_floor_words', '300', 'content', 'GH-234: prose word-count threshold above which the line-ratio sub-check kicks in. Per the issue spec, short posts (<300 words) don''t get the ratio check because a 200-word note doesn''t need a code-heavy layout to be valuable.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('code_density_min_blocks_per_700w', '1', 'content', 'GH-234: minimum fenced code blocks expected per 700 prose words in a tech post. The check skips posts under 200 prose words regardless. Set to 0 to disable just this sub-check.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('code_density_min_line_ratio_pct', '20', 'content', 'GH-234: minimum percentage of non-empty content lines that must live inside a fenced code block, applied only to posts above code_density_long_post_floor_words. Set to 0 to disable just this sub-check.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('code_density_tag_filter', 'technical,ai,programming,ml,python,javascript,rust,go', 'content', 'GH-234: comma-separated list of tag/topic tokens that qualify a post as ''tech'' for the code-block density rule. Matched case-insensitively against post tags + topic. Set to an empty string to disable the gate without touching the master flag.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_age_months', '6', 'identity', 'Company age in months (update periodically)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_founded_date', '2025-09-25', 'identity', 'Company founding date', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_founded_year', '2025', 'identity', 'Company founding year', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_founder_name', 'Matt', 'identity', 'Founder name', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_name', 'Glad Labs', 'identity', 'Legal company name', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_products', 'gladlabs.io,content pipeline,openclaw', 'identity', 'Known real products (for hallucination checks)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('company_team_size', '1', 'identity', 'Team size for content validation', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('compose_drift_auto_recover_enabled', 'false', 'monitoring', 'Brain compose-drift probe auto-recover toggle (#213). When ''false'' (default, safe), the probe only notifies the operator when it detects drift between docker-compose.local.yml and the running containers — the operator runs the manual fix (`docker compose -f docker-compose.local.yml up -d <drifted-services>`). When ''true'', the probe runs the recreate automatically via the Docker socket, waits for the containers to come back, and re-checks drift. Trade-off: auto-recreate cycles in-flight requests on the affected services for the recreate window, but stale spec is worse (missing mounts cause silent feature failures). Default ''false'' so a buggy probe can''t cause cascading recreates. Flip to ''true'' once you''re confident in the probe''s accuracy.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('compose_drift_skip_services', '', 'monitoring', 'Comma-separated list of compose service names the brain drift probe (#213) should skip. Useful for services with intentional spec drift (a sidecar hot-patched in place, a manually-edited container the operator doesn''t want to recreate). Empty by default — every service with a container_name in compose gets checked.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('compose_spec_path', '/app/docker-compose.local.yml', 'monitoring', 'Path to the docker-compose.yml the brain compose-drift probe (#213) reads. The brain container bind-mounts the host''s ./docker-compose.local.yml into this path read-only. Change this if your stack ships its compose file at a different path (e.g. /app/docker-compose.yml for the default-name variant). Setting an unreadable path degrades the probe to a structured ''unknown'' status without crashing the brain.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_max_refinement_attempts', '3', 'content', 'Max attempts to refine content quality', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_min_word_count', '800', 'content', 'Minimum word count for blog posts', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_quality_minimum', '75', 'pipeline', 'Minimum quality score to even queue for approval. Below this = auto-reject.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_router_contradiction_review_max_tokens', '1500', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
