INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_validator_warning_qa_penalty', '3', 'quality', 'Points subtracted from final QA score per validator warning (GH-91)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_validator_warning_reject_threshold', '5', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('content_weekly_cap', '3', 'pipeline', 'Maximum new posts per week (0=unlimited). Topic discovery respects this.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('cost_alert_threshold_pct', '80', 'cost', 'Alert when spend exceeds this % of limit', 'f', 't') ON CONFLICT (key) DO NOTHING;
