INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('default_media_to_generate', '', 'general', 'Comma-separated list of media to generate alongside each new post when --media isn''t passed. Empty = blog post only. Canonical names: podcast, video, short.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('default_model_tier', 'budget', 'pipeline', 'Default model cost tier (free/budget/standard/premium/flagship)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('default_ollama_model', 'auto', 'content', 'Default Ollama model for LLM calls. "auto" → OllamaClient picks the first available pulled model. Override with a specific model tag (e.g. "gemma3:27b").', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('default_workflow_gates', 'topic,draft,final', 'general', 'Comma-separated gate sequence applied to new posts when --gates isn''t passed. Empty string = fully autonomous (no human checkpoints). Canonical names: topic, draft, podcast, video, short, final.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('dev_diary_auto_publish_dry_run', 'true', 'publishing', 'When true (default), auto-publish gate runs in observe-only mode: logs ''would have auto-published Y/N'' for each finalize but never actually approves. Set to false ONLY after the dry-run logs show consistent agreement with operator manual approves over multiple runs.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('dev_diary_auto_publish_max_edit_distance', '50', 'publishing', 'Char-level edit distance threshold for the ''clean run'' criterion. Default 50 — trivial typo fixes pass; substantive rewording fails. Tune based on observed published_post_edit_metrics.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('dev_diary_auto_publish_min_clean_runs', '3', 'publishing', 'Trailing N publishes that must have edit_distance < auto_publish_max_edit_distance for the gate to fire. Default 3 — stricter than 1 to avoid one-good-run bias.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('dev_diary_auto_publish_threshold', '-1', 'publishing', 'Quality_score floor for dev_diary auto-publish. Default -1 disables the gate entirely. Set to a value 0-100 (e.g. 85) to opt into auto-publish for runs scoring at or above the floor. ALSO requires dev_diary_auto_publish_dry_run=false.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('dev_diary_last_run_date', '2026-05-08', 'scheduling', 'YYYY-MM-DD (UTC) of the last successful dev-diary job run. Idempotency marker — the job no-ops if this matches today.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('development_mode', 'false', 'general', 'Enable development mode', 'f', 't') ON CONFLICT (key) DO NOTHING;
