INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('discord_ops_webhook_url', '', 'notifications', 'Discord webhook URL for ops notifications. SECRET (the URL embeds the bearer token). Set via `poindexter settings set discord_ops_webhook_url <url>` after creating the webhook in Discord. Empty value disables Discord ops notifications cleanly per the no-silent-defaults rule.', 't', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_poll_interval_minutes', '5', 'monitoring', 'Cadence at which the brain runs the port-forward probe. Default 5 min matches the brain cycle so it runs every cycle.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_probe_enabled', 'true', 'monitoring', 'Master switch for the brain Docker port-forward stuck-state probe (#222). When false the probe short-circuits without scanning containers.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_probe_timeout_seconds', '3', 'monitoring', 'Per-HTTP-probe timeout in seconds. Kept tight (3s) so a stuck service can''t block the brain cycle on probes.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_recovery_wait_seconds', '5', 'monitoring', 'How long the probe waits after a docker restart before re-probing to confirm recovery. Default 5s lets Docker Desktop re-establish the wslrelay forward.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_restart_cap_per_window', '3', 'monitoring', 'Maximum number of times a single container may be restarted within the rolling window. Prevents runaway restart loops when the underlying issue is not actually a stuck port forward.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_restart_cap_window_minutes', '60', 'monitoring', 'Rolling window length in minutes for the per-container restart cap. Default 60 min — combined with the cap of 3 means at most 3 restarts of any one container per hour.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('docker_port_forward_watch_list', '[{"container": "poindexter-pyroscope", "port": 4040, "path": "/"}, {"container": "poindexter-glitchtip-web", "port": 8080, "path": "/"}, {"container": "poindexter-alertmanager", "port": 9093, "path": "/-/healthy"}, {"container": "poindexter-pgadmin", "port": 5480, "path": "/misc/ping"}, {"container": "poindexter-grafana", "port": 3000, "path": "/api/health"}, {"container": "poindexter-prometheus", "port": 9090, "path": "/-/healthy", "host_port": 9091}, {"container": "poindexter-loki", "port": 3100, "path": "/ready"}, {"container": "poindexter-langfuse-web", "port": 13000, "path": "/api/public/health"}, {"container": "poindexter-clickhouse", "port": 8123, "path": "/ping"}, {"container": "poindexter-minio", "port": 9000, "path": "/minio/health/live"}, {"container": "poindexter-redis-insight", "port": 5540, "path": "/healthcheck"}, {"container": "poindexter-pyroscope-grafana-frontend", "port": 4045, "path": "/"}]', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('electricity_rate_kwh', '0.2579', 'cost', 'RI Energy Last Resort Service rate $0.14770/kWh (verified by Matt)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_age_days', '14', 'memory', 'Days before raw embeddings get clustered + summarized into a single is_summary=TRUE row by CollapseOldEmbeddingsJob. Set to <21 (claude_sessions TTL) so collapse runs BEFORE TTL pruning hard-deletes the originals.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_cluster_size', '8', 'memory', 'GH-81: target cluster count per (source_table, age-group) when the collapse job runs k-means over candidate embeddings. The effective k is min(cluster_size, candidate_count // 2) so small groups fall back to fewer clusters. 8 gives ~8x reduction on a typical ~64-row group.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_enabled', 'true', 'memory', 'GH-81: master switch for the embeddings collapse job. When true, the scheduled job clusters old rows per source_table, writes one summary row per cluster, and deletes the originals. Defaults to false so existing deployments are unaffected until an operator opts in.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_source_tables', 'claude_sessions,brain,audit', 'memory', 'GH-81: comma-separated list of source_table values the collapse job is allowed to touch. posts/issues/memory are deliberately NOT in this list — they''re queried by the live pipeline and must retain raw embeddings. Operators may add/remove entries but should never include an authoritative source here.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_summary_model', 'gemma3:27b-it-qat', 'memory_compression', 'Ollama model used for cluster-summary generation. Picked empirically: factually dense, no thinking-trace overhead, ~12s/5-excerpt cluster on the RTX 5090. Override via app_settings if a smaller/larger model fits the operator''s GPU bandwidth better.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_summary_provider', 'ollama', 'memory_compression', 'Summarization backend for CollapseOldEmbeddingsJob. ''ollama'' calls the local LLM to produce a real summary; ''joined_preview'' falls back to the legacy joined-text heuristic (used when ollama is unreachable, also a no-LLM-cost mode). Defaults to ''ollama'' as of migration 0127.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_collapse_summary_timeout_seconds', '60', 'memory_compression', 'Per-call timeout for the LLM summary generation. 60s allows headroom over the ~12s typical run; on timeout the cluster falls back to joined-preview rather than failing the whole collapse pass.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_model', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.audit', '90', 'general', 'Days to keep audit_log embeddings before prune_stale_embeddings drops them. 90d covers the typical operator post-mortem window.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.brain', '365', 'general', 'Days to keep brain_knowledge embeddings before prune. Brain memory is designed to compound; long horizon by design.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.claude_sessions', '21', 'general', 'Days to keep Claude Code session embeddings before prune_stale_embeddings drops them. 21d balances semantic-search recency against keeping enough history for cross-session recall.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.issues', '', 'general', 'Empty = no TTL. Issue embeddings are never auto-pruned — irreplaceable pipeline state.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.memory', '', 'general', 'Empty = no TTL. Memory embeddings are never auto-pruned — operator''s curated state.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embedding_retention_days.posts', '', 'general', 'Empty = no TTL. Post embeddings are never auto-pruned — feed live RAG retrieval.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('embed_model', 'nomic-embed-text', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enabled_topic_sources', 'knowledge,codebase,hackernews,devto,web_search', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_featured_image', 'true', 'image', 'Generate/search featured images for posts', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_mcp_server', 'true', 'features', 'Enable Model Context Protocol server', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_memory_system', 'true', 'features', 'Enable agent memory system', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_pyroscope', 'true', 'observability', 'When true, services/profiling.py:setup_pyroscope() configures the pyroscope-io agent at worker / brain / voice-agent startup so each process ships CPU profiles to the Pyroscope server at pyroscope_server_url (default http://pyroscope:4040). Default flipped to true in Glad-Labs/poindexter#406. Set to false to disable continuous profiling fleet-wide without rebuilding any images — the agent picks up the change on next service restart.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_sdxl_warmup', 'false', 'general', 'Warm up SDXL models on startup', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_semantic_dedup', 'true', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_tracing', 'true', 'observability', 'Master switch for OpenTelemetry tracing. When true, services.tracing.setup_tracing initializes the TracerProvider + OTLP gRPC exporter and instruments FastAPI for HTTP request spans. Lifespan-time read; toggle requires worker restart.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_training_capture', 'false', 'features', 'Enable training data capture from pipeline runs', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('enable_writer_self_review', 'false', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('environment', 'development', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('flux_schnell_server_url', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_auto_expire_batch_size', '50', 'gates', 'Cap per-cycle expiry to this many gates to avoid huge batches. Excess rolls over to the next cycle.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_auto_expire_enabled', 'true', 'gates', 'Master switch for the brain gate auto-expire probe (#338). When false, the probe short-circuits without scanning gates.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_auto_expire_notify_threshold', '1', 'gates', 'Only ping the operator (Telegram coalesced) when batch size >= this. Default 1 = always notify on any expiry.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_auto_expire_poll_interval_minutes', '30', 'gates', 'Cadence at which the brain runs the auto-expire probe. Stale gates aren''t time-sensitive, so 30-min default is sparse on purpose.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_pending_max_age_hours', '168', 'gates', 'Pending gates older than this many hours get auto-rejected with a sentinel reason. Default 168h = 7 days, per the #338 spec — operator should set lower if they want stricter SLA.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_pending_summary_discord_per_cycle', 'false', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_pending_summary_enabled', 'true', 'gates', 'Master switch for the brain gate-pending-summary probe (#338). When false, the probe short-circuits without scanning post_approval_gates and no coalesced summary is sent. The per-flip Discord ping in services/gates/post_approval_gates.notify_gate_pending stays on regardless.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_pending_summary_min_age_minutes', '60', 'gates', 'Grace window after the OLDEST pending gate''s creation before the first Telegram page fires. Prevents paging the operator the instant a gate appears -- they get 60 min to triage on their own before the system escalates.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_pending_summary_poll_interval_minutes', '60', 'gates', 'Cadence at which the probe re-scans the pending queue. Hourly per #338 spec. Brain cycle is 5 min so the probe internally rate-limits via this setting (it runs every cycle but no-ops between intervals -- the Discord per-cycle ping uses the inner interval, not this one).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_pending_summary_telegram_dedup_minutes', '60', 'gates', 'Suppress duplicate Telegram pings within this window when the queue size has not grown past gate_pending_summary_telegram_growth_threshold. Combined with the growth threshold, this prevents re-paging when the queue is the same as last cycle but DOES re-page when N new gates landed.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gate_pending_summary_telegram_growth_threshold', '3', 'gates', 'Re-fire the coalesced Telegram ping inside the dedup window if the pending queue grew by STRICTLY MORE than this many gates since the last ping. Default 3 means: queue went 5->8 (delta=3, not >3) -> no re-ping; queue went 5->9 (delta=4) -> re-ping. Set to 0 to re-ping on any growth, or to a very large number to disable growth-triggered re-pings entirely.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gh_repo', 'Glad-Labs/glad-labs-stack', 'integrations', 'GitHub repository (``owner/name``) the dev_diary topic source queries for merged PRs and notable commits when assembling the daily build-in-public context bundle. Read by services/topic_sources/dev_diary_source.py via direct GitHub REST API calls (``GET /repos/{repo}/pulls`` + ``GET /repos/{repo}/commits``). Pair with the ``gh_token`` secret for authenticated rate limits + private-repo access. Defaults to the Glad Labs operator monorepo; OSS operators on the public Poindexter distribution should point this at their own repo. Closes Glad-Labs/poindexter#405.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gitea_repo', 'gladlabs/glad-labs-codebase', 'integration', 'Gitea repository (owner/name)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gitea_url', 'http://localhost:3001', 'integration', 'Gitea server URL', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gitea_user', 'gladlabs', 'integration', 'Gitea username', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_base_url', 'http://glitchtip-web:8000', 'monitoring', 'Base URL for the GlitchTip API the brain triage probe queries. Default is the compose-internal hostname; brain.docker_utils.localize_url() rewrites it to host.docker.internal:8080 when the brain runs on the host. Override only if you''re running GlitchTip outside the default poindexter compose stack.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_triage_alert_threshold_count', '100', 'monitoring', 'Brain triage probe pages via notify_operator() when a GlitchTip issue has count >= this AND matches no entry in glitchtip_triage_auto_resolve_patterns. Default 100 keeps noise quiet while still surfacing genuinely-recurring novel errors. Per-issue dedupe by id within a single brain process uptime — restart the brain to re-page.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_triage_auto_resolve_patterns', E'[{"title_pattern": "Failed to export span batch.*langfuse-web", "action": "resolve", "reason": "Langfuse OTel exporter retries on its own when langfuse-web restarts. Closing as expected transient noise. If langfuse-web is consistently unreachable that''s a separate compose-drift / container-down issue that the compose_drift probe will catch.", "max_count": null, "level_in": null}, {"title_pattern": "\\\\\\\\x1b\\\\\\\\[\\\\\\\\d+m\\\\\\\\d{4}-\\\\\\\\d{2}-\\\\\\\\d{2}T", "action": "resolve", "reason": "ANSI-decorated structlog line. GlitchTip splits these into a separate ''issue'' per task ID, which is noise \\\\u2014 the parent exception is captured as its own (deduplicated) issue. Resolving these does not lose information.", "max_count": 50, "level_in": null}, {"title_pattern": "^\\\\\\\\[error\\\\\\\\s*\\\\\\\\]\\\\\\\\s*=+", "action": "resolve", "reason": "Decorative ''===='' banner emitted by structlog when the pipeline prints a multi-line error block. Not a real error on its own \\\\u2014 the actual exception is captured separately.", "max_count": null, "level_in": null}, {"title_pattern": "^\\\\\\\\[error\\\\\\\\s*\\\\\\\\]\\\\\\\\s*Failed to update task [a-f0-9-]{36}", "action": "resolve", "reason": "Per-task update failure \\\\u2014 symptom of a deeper bug (worker loses track of a task ID). The parent exception is captured as its own issue; these per-task lines are duplicate noise. max_count gate so a real update-system meltdown still pages.", "max_count": 20, "level_in": null}, {"title_pattern": "ModuleNotFoundError:.*cofounder_agent", "action": "resolve", "reason": "Stale dev process trying to import the package by its old name. Real workers import from `services.*` and don''t trigger this. Resolving on sight.", "max_count": null, "level_in": null}, {"title_pattern": "AllModelsFailedError|ALL AI MODELS FAILED|Ollama:\\\\\\\\s+False|Stage ''generate_content'' halted", "action": "ignore", "reason": "Already tracked elsewhere \\\\u2014 the model-router fallback chain and Ollama liveness probes both surface this, and the audit showed all of these strings (the bare exception name, the structlog ''ALL AI MODELS FAILED'' line, the ''Ollama: False'' stage diagnostic, and the ''generate_content halted'' RuntimeError wrapper) burst together during a single Ollama outage. Marking ''ignore'' (not ''resolve'') so operators can still see them in the GlitchTip UI for triage, but the brain probe stops paging on them.", "max_count": null, "level_in": null}]', 'monitoring', 'JSONB array of triage rules for the brain GlitchTip probe. Each entry: {title_pattern: <regex>, action: ''resolve'' or ''ignore'', reason: <text>, max_count: <int|null>, level_in: [<level>...] | null}. Default rules derived from the 2026-05-01 audit of 506 open issues — Langfuse exporter spam, ANSI-decorated structlog duplicates, decorative banner lines, per-task update failures, stale cofounder_agent imports, and AllModelsFailedError (ignore-only since the model-router and Ollama probes already cover it). Edit this setting to add tenant-specific rules without code changes.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_triage_enabled', 'true', 'monitoring', 'Master enable for the brain GlitchTip triage probe. When ''true'' (default), the probe runs every cycle (5-min), pulls open issues, auto-resolves matches against glitchtip_triage_auto_resolve_patterns, and pages on novel high-count issues. Set to ''false'' to silence it (e.g. while GlitchTip itself is being upgraded).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('glitchtip_triage_org_slug', 'glad-labs', 'monitoring', 'GlitchTip organization slug the brain triage probe queries. Default ''glad-labs'' matches the org the bootstrap installer creates. Change this if you renamed the org in the GlitchTip UI.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('google_gemini_credit', '1000', 'finance', 'Google developer program Gemini credit (unused)', 'f', 't') ON CONFLICT (key) DO NOTHING;
