INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gpu_model', 'NVIDIA RTX 5090 (32GB VRAM)', 'identity', 'GPU model for brain knowledge', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gpu_name', '', 'general', 'GPU model name (auto-detected by detect-hardware.py)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gpu_temperature_high_threshold_c', '85', 'monitoring', 'GPU core temperature (C) above which the brain `gpu_temperature` probe alerts. RTX 5090 hard-throttles around 90C; 85 is the "phone Matt" line. Tunable to taste.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('gpu_vram_gb', '0', 'general', 'GPU VRAM in GB (auto-detected by detect-hardware.py)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('grafana_alert_sync_enabled', 'true', 'monitoring', 'Master switch for the brain daemon''s Grafana alert sync loop. Set to ''false'' to disable the loop entirely without removing rules. Ref: GH-28.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('grafana_alert_sync_interval_cycles', '3', 'monitoring', 'How many brain cycles (5 min each) between Grafana alert syncs. Default 3 = 15 min. Lowering this makes alert rule changes propagate faster at the cost of API chatter. Ref: GH-28.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('grafana_api_base_url', 'http://poindexter-grafana:3000', 'monitoring', 'Grafana base URL the brain daemon uses to push alert rules and contact points. Defaults to the docker-compose service name, reachable from the brain container. Override for externally-hosted Grafana. Ref: GH-28.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('grafana_url', 'http://localhost:3000', 'integration', 'Grafana Cloud instance URL', 'f', 't') ON CONFLICT (key) DO NOTHING;
