INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('indexnow_key', '', 'seo', 'IndexNow API key for instant search-engine notification. SECRET — the key file at <site>/<key>.txt proves ownership of the IndexNow account. Set via `poindexter settings set indexnow_key <key>` and host the matching `<key>.txt` at the site root. Empty disables IndexNow pings cleanly.', 't', 't') ON CONFLICT (key) DO NOTHING;
