INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('langfuse_host', 'http://localhost:3010', 'observability', 'Langfuse base URL for prompt management + tracing. Default empty = Langfuse disabled, prompts resolve via DB+YAML fallback. Set to e.g. http://localhost:3010 (local container) or your Langfuse Cloud URL to enable. UnifiedPromptManager picks up the change on the next worker restart.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('langfuse_public_key', '', 'observability', 'Langfuse project public key (pk-lf-...). Paired with langfuse_secret_key (already is_secret=true). Marked is_secret=true on 2026-05-12 to keep the project identifier out of the public mirror — even though the public key alone cannot authenticate writes, it identifies the operator''s Langfuse project. Set via `poindexter settings set langfuse_public_key <pk-lf-…>`.', 't', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('langfuse_tracing_enabled', 'true', 'observability', 'When true (default), LiteLLMProvider registers Langfuse as a success/failure callback so every LLM call emits a span to the Langfuse host configured via langfuse_host + langfuse_public_key + langfuse_secret_key (migration 0153). Set to false to disable tracing without affecting Langfuse prompt management — useful if the Langfuse stack is unhealthy and you don''t want LLM calls paying the failed-callback latency cost. Note: the Langfuse Python SDK already batches + retries spans and never blocks the calling LLM request, so this kill switch is mostly defensive.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('local_database_url', 'postgresql://poindexter:poindexter-brain-local@postgres-local:5432/poindexter_brain', 'system', 'Local brain DB connection string (Docker internal)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('local_llm_api_url', 'http://host.docker.internal:11434', 'content', 'Ollama API base URL for local LLM calls (e.g. http://localhost:11434). Empty value means ''Ollama not configured'' — callers must handle that explicitly per the no-silent-defaults rule. Ref: GH-175.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('local_llm_model_name', 'auto', 'content', 'Ollama model fallback used by agents/content_agent/config when no per-task model is configured. ''auto'' lets OllamaClient pick the first available pulled model. Override with a specific tag (e.g. ''gemma3:27b''). Ref: GH-175.', 'f', 't') ON CONFLICT (key) DO NOTHING;
