INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('media_generation_retry_limit', '2', 'general', 'How many times each per-medium generation may fail before the system escalates to a media_generation_failed gate that asks the operator what to do.', 'f', 't') ON CONFLICT (key) DO NOTHING;
