INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('memory_compression_excerpts_per_bucket', '12', 'memory_compression', 'How many sample rows feed the LLM prompt and land in the {event_type}_excerpts JSONB column for each day-bucket. 12 is a balance between prompt size and giving the model enough context to write a useful summary.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('memory_compression_summary_model', 'gemma3:27b-it-qat', 'memory_compression', 'Ollama model used by retention.summarize_to_table for the per-day summary paragraph. Same default as embedding_collapse_summary_model for consistency — a single model swap covers both compression paths.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('memory_compression_summary_timeout_seconds', '60', 'memory_compression', 'Per-call timeout (seconds) for the LLM summary generation in retention.summarize_to_table. On timeout the handler falls back to a joined-preview summary so a slow LLM doesn''t kill the whole retention pass.', 'f', 't') ON CONFLICT (key) DO NOTHING;
