INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('migration_drift_auto_recover_enabled', 'false', 'monitoring', 'Brain migration-drift probe behavior (#228). When ''false'' (default, safe), the probe ONLY notifies the operator when it detects unapplied migrations on the worker — the operator runs the manual fix (`docker restart poindexter-worker`). When ''true'', the probe runs the restart automatically via the Docker socket, waits 60s for the worker to come back healthy, and re-checks drift. Trade-off: auto-restart may interrupt in-flight requests for ~60s but stale schema is worse (writes against new tables fail). Default ''false'' so a bad migration that''s crash-looping the worker isn''t masked by an auto-restart loop. Flip to ''true'' once you''re confident in your migration pipeline.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('min_curation_score', '75', 'pipeline', 'Minimum QA score to surface for human review (below this = auto-reject)', 'f', 't') ON CONFLICT (key) DO NOTHING;
