INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('morning_brief_hour_local', '7', 'monitoring', 'Local-time hour the morning_brief job fires (informational; the active schedule lives in the Job class cron expression). Surfaced here so an operator dashboard can show the configured hour.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('morning_brief_lookback_hours', '24', 'monitoring', 'Lookback window in hours used to roll up published posts, awaiting_approval entries, failed tasks, alert counts, costs, and brain probe activity.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('morning_brief_telegram_critical_only', 'true', 'monitoring', 'When true the brief only pings Telegram on critical-severity alerts or failed tasks (Discord still always receives the full brief). Set false to also ping Telegram on quiet mornings.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_batch_delay_seconds', '2', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_batch_size', '50', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_email', '', 'general', 'Newsletter sender email (legacy)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_enabled', 'true', 'newsletter', 'Enable newsletter sending on publish', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_from_email', 'Glad Labs <newsletter@gladlabs.io>', 'identity', 'Newsletter sender address', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_from_name', 'Glad Labs', 'newsletter', 'Newsletter sender display name', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('newsletter_provider', 'resend', 'newsletter', 'Email provider: resend or smtp', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_batch_expires_days', '7', 'niche_pivot', 'Number of days a topic_batch row stays open before its expires_at watermark trips. Default 7 matches the prior hardcoded timedelta(days=7) in TopicBatchService._write_batch. Higher = give the operator more time to rank/resolve a batch; lower = force timely operator action.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_carry_forward_decay_factor', '0.7', 'niche_pivot', 'Multiplicative decay applied to a candidate''s decay_factor each time it survives a batch unpicked. Default 0.7 matches the prior hardcoded literal in TopicBatchService._load_carry_forward — by the third batch a candidate has decayed to 0.7^3 = 0.343 of its original score. Lower = more aggressive (older candidates fall off the rank list faster); higher = stickier (the same topic keeps resurfacing for many batches).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_embedding_model', 'nomic-embed-text', 'niche_pivot', 'Ollama embedding model used for niche topic ranking and writer-mode RAG snippet retrieval. Default ''nomic-embed-text'' matches the prior hardcoded literal in topic_ranking.py (_embed_text_cached). Override with another locally-pulled embedding model (must produce 768-dim vectors to match embeddings.embedding column type).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_goal_descriptions', '{"TRAFFIC": "Topic likely to attract organic search traffic; trending keyword, broad appeal, evergreen demand.", "EDUCATION": "Topic that teaches the reader something concrete and useful they didn''t know before.", "BRAND": "Topic that reinforces the operator''s positioning and unique perspective.", "AUTHORITY": "Topic that demonstrates the operator''s depth and expertise on something specific.", "REVENUE": "Topic that drives a commercial outcome: signups, sales, conversions, paid feature awareness.", "COMMUNITY": "Topic that resonates with the operator''s existing audience; sparks discussion, shares, replies.", "NICHE_DEPTH": "Topic that goes deep on the operator''s niche specialty rather than broad-audience content."}', 'niche_pivot', 'JSON blob mapping each goal_type (TRAFFIC, EDUCATION, BRAND, AUTHORITY, REVENUE, COMMUNITY, NICHE_DEPTH) to the prose anchor used to compute its goal vector embedding. Operators tune the prose to nudge what each goal weight ''means'' for their niche. Follow-up: extract to a dedicated niche_goal_prompts (niche_id, goal_type) table so each operator can override per-niche; current single-blob shape is a system-wide override that mirrors the prior dict constant in topic_ranking.py.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_internal_rag_per_kind_limit', '4', 'niche_pivot', 'Per-source-kind limit passed to InternalRagSource.generate by TopicBatchService._discover_internal. Default 4 matches the prior hardcoded literal — pulls 4 most-recent items from each of {claude_session, brain_knowledge, audit_event, decision_log, memory_file, post_history} per discovery sweep. Higher = larger candidate pool, more LLM tokens spent on distillation; lower = faster sweep, cheaper.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_internal_rag_snippet_max_chars', '600', 'niche_pivot', 'Per-snippet character cap when joining raw snippets into the topic/angle distillation prompt in InternalRagSource._distill_topic_angle. Default 600 matches the prior hardcoded slice (s[:600]). Higher = more context per snippet, larger prompt; lower = tighter prompt, faster + cheaper distillation.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_ollama_chat_timeout_seconds', '60', 'niche_pivot', 'HTTP timeout (seconds) for direct Ollama /api/chat calls made by topic_ranking._ollama_chat_json — used by the LLM scorer, internal RAG distillation, story_spine outline pass, and two_pass revise pass. Default 60 matches the prior hardcoded httpx timeout. Higher = tolerate slower local models; lower = fail fast on a wedged Ollama.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('niche_top_n_per_pool', '5', 'niche_pivot', 'Top N candidates per pool (external + internal) carried forward from the embedding pre-rank into the LLM final-score stage. Default 5 matches the prior hardcoded slice in TopicBatchService._embed_and_pre_rank and run_sweep (top10 = pool_external[:5] + pool_internal[:5]). Higher = wider LLM prompt, more candidates to rank; lower = tighter shortlist, cheaper LLM call.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('nvidia_exporter_url', 'http://host.docker.internal:9835/metrics', 'general', 'nvidia-smi metrics exporter', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('oauth_issuer_url', 'https://nightrider.taild4f626.ts.net', 'security', 'Public-facing issuer URL advertised in RFC 8414 metadata. Falls back to request.url when empty (e.g. localhost dev).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_base_url', 'http://host.docker.internal:11434', 'general', 'Ollama API endpoint', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_client_timeout_seconds', '1500', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_concurrency_limit', '10', 'performance', 'Maximum concurrent in-flight Ollama requests this worker process will issue — passed to aiolimiter.AsyncLimiter. Prevents bursts of pipeline tasks from VRAM-thrashing the GPU and silently falling back to a smaller model. Tune down on shared GPUs, up on a dedicated rig. Live changes apply via services.ollama_client.rebuild_concurrency_limiter() or a worker restart.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_electricity_cost_per_1k_tokens', '0.000256', 'cost', 'Ollama electricity cost per 1K tokens (USD)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_max_retries', '3', 'performance', 'Maximum number of attempts (initial + retries) for Ollama generate_with_retry. Passed to tenacity''s stop_after_attempt. Default 3 = 1 try + 2 retries. Lower this if you''d rather fail-fast to the cloud fallback chain; raise it on a flaky local Ollama.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_num_ctx', '8192', 'gpu', 'Ollama context window size — limits KV cache VRAM usage', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_retry_initial_seconds', '1', 'performance', 'Initial backoff delay (seconds) for Ollama retries — passed to tenacity''s wait_exponential_jitter(initial). Doubles on each subsequent retry up to ollama_retry_max_seconds, with up to 2s jitter.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ollama_retry_max_seconds', '30', 'performance', 'Upper bound (seconds) on Ollama retry backoff — passed to tenacity''s wait_exponential_jitter(max). Caps the exponential growth so a long retry chain can''t stretch into multi-minute waits.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('openclaw_gateway_url', 'http://localhost:18789', 'general', 'OpenClaw gateway URL', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('openclaw_webhook_url', '', 'webhooks', 'OpenClaw webhook delivery URL', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('operator_id', 'operator', 'general', 'Default operator ID', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('operator_url_probe_skip_keys', 'social_x_url,social_linkedin_url,oauth_issuer_url,public_site_revalidate_url,gitea_url,r2_public_url,sdxl_server_url,voice_agent_ollama_url,preview_base_url', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_audit_logged', 'true', 'firefighter', 'When true, every triage call writes an audit_log row tagged source=''ops_triage'' (success or failure). When false, only successful follow-up posts are observable. Default true so operators can grep audit_log for triage history. #347.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_cache_ttl_seconds', '3600', 'firefighter', 'TTL (seconds) for the POST /api/triage process-local idempotency cache (#347 step 3). Repeat calls for the same alert_event_id within this window return the cached diagnosis instead of re-invoking the LLM. Set lower while iterating on the system prompt to force re-calls; set higher to absorb brain retry storms without budget impact.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_enabled', 'true', 'firefighter', 'Master kill-switch for the firefighter ops LLM (#347). When false, alert_dispatcher skips the parallel triage task and operators only see the raw alert. Flip without redeploy.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_max_context_tokens', '4000', 'firefighter', 'Cap on the pre-fetched context size handed to the LLM. When the assembled context (alert + history + audit_log + pipeline_tasks + app_settings snapshot) would exceed this, firefighter_service truncates oldest audit_log rows first. Rough 4-chars-per-token approximation. #347.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_max_diagnosis_tokens', '400', 'firefighter', 'Cap on the diagnosis output length (Telegram-friendly). The service truncates with a ''[...]'' marker if the LLM exceeds this. Rough 4-chars-per-token approximation. #347.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_model_class', 'ops_triage', 'firefighter', 'model_router tier the firefighter_service uses for triage (#347). Defaults to a dedicated ''ops_triage'' class which maps to free / glm-4.7-5090 in the model_router tier table. Change to ''standard'' / ''budget'' / etc. to A/B alternative writers.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_retry_backoff_seconds', '[10, 30, 90]', 'firefighter', 'JSON list of per-attempt sleep durations (seconds) the brain uses between retries when worker /api/triage is unreachable. Length should equal ops_triage_retry_max. #347.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_retry_max', '3', 'firefighter', 'Maximum retry attempts when the brain can''t reach the worker /api/triage endpoint. Retries are scheduled with the backoff from ops_triage_retry_backoff_seconds. #347.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('ops_triage_system_prompt', 'You are the Poindexter operator. The system you are diagnosing is the Poindexter content pipeline -- a self-hosted FastAPI worker, brain daemon, Postgres + pgvector, Ollama for LLM inference. You will be shown an alert + curated database state. Your job is to write ONE SHORT PARAGRAPH (<=400 tokens) explaining: what likely happened, why you think so (cite the rows you saw), and one suggested next step the operator could take. Do NOT propose code changes -- those go to a different escalation path. Do NOT suggest ALL POSSIBLE causes -- commit to your most likely diagnosis. If the context is genuinely ambiguous, say so plainly and stop.', 'firefighter', 'Operator-persona system prompt the triage LLM sees. Iterable without redeploy. Keep <=400 tokens; the prompt sets the voice (one paragraph, commit to most-likely diagnosis, no code suggestions). #347.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('otel_exporter_otlp_endpoint', 'http://tempo:4317', 'observability', 'OTLP gRPC endpoint that the worker pushes spans to. Default points at the docker-compose tempo service on its OTLP gRPC port. Change to a remote tempo or a collector if needed.', 'f', 't') ON CONFLICT (key) DO NOTHING;
