INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('premium_active', 'false', 'experiments', 'When ''true'', UnifiedPromptManager loads prompt_templates rows where source=''premium'' on top of source=''default''. When ''false'' (OSS default), only ''default'' rows load. Set to ''true'' after applying a Glad Labs Premium Prompts pack (Pro tier, delivered via Lemon Squeezy).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('preview_base_url', 'http://100.81.93.12:8002', 'notifications', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('privacy_email', 'privacy@gladlabs.io', 'identity', 'Privacy/GDPR contact email', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('probe_webhook_freshness_enabled', 'true', 'monitoring', 'Master switch for the brain''s webhook-freshness probe. When true, the probe checks revenue_events / subscriber_events row freshness on its cycle and notifies the operator if either table has gone quiet beyond its threshold. Disable to silence the alert (e.g. pre-revenue, while you''re still configuring providers).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('probe_webhook_freshness_interval_minutes', '1440', 'monitoring', 'How often the webhook-freshness probe runs (minutes). Default 1440 = once a day. The probe is cheap (two SELECT MAX queries) but the alerts are noisy if it fires hourly — daily catches real outages within a day, which is the right SLA for a passive revenue stream.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prometheus.threshold.daily_spend_critical_usd', '5.0', 'prometheus', 'Daily LLM spend critical threshold', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prometheus.threshold.daily_spend_warning_usd', '4.0', 'prometheus', 'Daily LLM spend warning threshold', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prometheus.threshold.embeddings_stale_seconds', '21600', 'prometheus', 'Seconds without an embeddings_total change before EmbeddingsStale fires', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('prometheus.threshold.monthly_spend_warning_usd', '15.0', 'prometheus', 'Monthly LLM spend warning threshold', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_dedup_hours', '12', 'monitoring', 'Quiet period (in hours) after a stale-PR alert fires before the same PR can re-page. Per-PR dedup is anchored on the fingerprint pr_stale_<repo>_<pr_number> in alert_dedup_state. Default 12 re-pings the operator twice a day if they forgot once.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_max_prs_per_alert', '5', 'monitoring', 'Cap on the number of PRs surfaced in a single Discord-ops message body. Keeps the alert under Discord''s per-message ceiling and stops a runaway backlog from producing an unreadable card. Surplus PRs are summarized as ''and N more''.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_min_hours', '24', 'monitoring', 'Minimum age (in hours) before an open PR is considered stale by the brain PR staleness probe. PRs younger than this are skipped before the per-PR check-runs lookup so the probe doesn''t burn rate-limit budget on fresh work.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_poll_interval_minutes', '60', 'monitoring', 'Internal cadence gate for the brain PR staleness probe. The brain dispatches the probe every cycle (~5 min); the actual GitHub round-trip only fires once per this interval. Default 60 = once an hour.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_probe_enabled', 'true', 'monitoring', 'Master switch for the brain PR staleness probe. When false the probe short-circuits without hitting GitHub. See brain/pr_staleness_probe.py.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('pr_staleness_repo', 'Glad-Labs/glad-labs-stack', 'monitoring', 'GitHub repository (``owner/name``) the brain PR staleness probe scans for open PRs. Future-proofs for multi-repo. Pair with the ``gh_token`` secret for authenticated rate limits + private-repo access.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('public_site_revalidate_url', 'https://www.gladlabs.io/api/revalidate', 'site', 'Full URL of the Next.js public site''s /api/revalidate endpoint. POSTed by services/revalidation_service.py to bust the ISR cache after every publish. Override per-environment (e.g. point at a Vercel preview URL for staging). Leave blank to fall back to the legacy resolution chain (public_site_url/site_url + /api/revalidate). Glad-Labs/poindexter#327.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('public_site_url', 'https://www.gladlabs.io', 'site', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
