INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('seed_url_fetch_timeout_seconds', '10', 'pipeline', 'URL-based topic seeding: total HTTP timeout (seconds) for the seed_url fetch on POST /api/tasks. Short by design — if a source page takes >10s to respond we''d rather reject the task with a clear 400 than tie up an API worker. Ref: GH-42.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('seed_url_max_bytes', '1048576', 'pipeline', 'URL-based topic seeding: hard cap (bytes) on the decoded response body. Guards against pathological pages that would OOM the API worker before title extraction runs. 1 MiB is plenty for any real article''s <title>/<h1>/<meta>. Ref: GH-42.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('seed_url_user_agent', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36', 'pipeline', 'URL-based topic seeding: User-Agent header for the seed_url fetch. Chrome-ish by default because many news/publisher sites 403 requests-default or urllib UAs. Operators can swap in a branded UA once they''ve set up outbound allowlists. Ref: GH-42.', 'f', 't') ON CONFLICT (key) DO NOTHING;
