INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_alert_dedup_minutes', '360', 'monitoring', 'Don''t re-fire the same (drive, attribute) alert within this many minutes. Default 360 (6 h) matches the default poll interval — one alert per attribute per cycle, max.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_current_pending_threshold', '0', 'monitoring', 'Inclusive threshold for Current_Pending_Sector. Anything strictly greater fires a warning. 0 = any pending sector at all (recommended — pending sectors precede reallocations).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_drive_filter', '', 'monitoring', 'Optional comma-separated list of drive names (e.g. /dev/sda,/dev/nvme0) to restrict scanning to. Empty = scan everything `smartctl --scan-open` finds.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_enabled', 'true', 'monitoring', 'Master switch for the brain SMART monitor probe (#387). When false, the probe short-circuits without scanning drives.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_poll_interval_hours', '6', 'monitoring', 'Cadence at which the brain runs `smartctl -a` against each detected drive. Default 6h matches typical SMART attribute update cadence.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_power_on_hours_info_threshold', '50000', 'monitoring', 'Power_On_Hours threshold above which the probe emits an info-severity FYI alert. ~50k h = ~5.7 years; useful for replacement-planning, not an emergency.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_reallocated_sector_threshold', '0', 'monitoring', 'Inclusive threshold for Reallocated_Sector_Ct. Anything strictly greater fires a warning alert. 0 = any reallocated sector at all is a warning (most aggressive — recommended).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_smartctl_path', '', 'monitoring', E'Absolute path to the smartctl binary. Empty = use shutil.which("smartctl"). Override when smartmontools is installed somewhere unusual (e.g. C:\\\\Program Files\\\\smartmontools\\\\bin\\\\smartctl.exe).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('smart_monitor_wear_leveling_warn_percent', '90', 'monitoring', 'Used-life percentage for SSD Wear_Leveling_Count above which the probe fires a warning. Computed as (100 - normalized_value) for the SMART attribute. Default 90 = warn when only 10% endurance remains.', 'f', 't') ON CONFLICT (key) DO NOTHING;
