INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('social_distribution_platforms', 'bluesky', 'social', 'GH-36: Comma-separated list of platforms social_poster should push to after a successful publish. Valid values: ''bluesky,mastodon''. Leave empty to disable direct publishing entirely (Telegram/Discord notifications still fire). LinkedIn/Reddit/YouTube adapters were removed in the 2026-05-08 services audit cleanup — see poindexter#40 (LinkedIn), poindexter#448 (Reddit), poindexter#449 (YouTube) for OAuth setup checklists.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('social_linkedin_url', 'https://www.linkedin.com/in/matthew-gladding-58b251387', 'social', 'LinkedIn profile URL', 'f', 't') ON CONFLICT (key) DO NOTHING;
