INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('support_email', 'support@gladlabs.io', 'identity', 'Support contact email', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('system_idle_watts', '120', 'cost', 'Total system idle power draw in watts (CPU+RAM+disk+GPU)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('task_executor_idle_alert_threshold_seconds', '1800', 'pipeline', 'Seconds the executor may sit on pending tasks without starting one before logging CRITICAL. Default 300 was firing every 25-30 min due to legitimate approval-queue throttling + 30-min content generation cycles — false alarm flooding Sentry. Raised to 1800 (30 min) so only real stalls trigger.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('task_failure_alert_dedup_window_seconds', '900', 'alerts', 'Suppress duplicate task-failure alerts for the same (task_id, error_message_hash) within this window. Default 900 (15 min). Set to 0 to disable dedup. Per Glad-Labs/poindexter#370.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('task_failure_alert_severity', 'discord', 'alerts', 'Channel routine task-failure alerts route to: ''discord'' (default, the spam channel) or ''telegram'' (escalates to operator''s phone). Per feedback_telegram_vs_discord, Telegram is reserved for the critical-alert list (worker offline, GPU temp, cost overrun, failure-rate breach) — a single bad task should not page the operator. Glad-Labs/poindexter#370.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('task_retry_backoff_initial_seconds', '60', 'alerts', 'Exponential-backoff base for auto-retry. Attempt N becomes eligible only after backoff * 2^(N-1) seconds have passed since the last failure. Only meaningful when task_retry_max_attempts > 0. Glad-Labs/poindexter#370.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('task_retry_max_attempts', '0', 'alerts', 'Max automatic re-claims of a ''failed'' task by _auto_retry_failed_tasks. Default 0 disables auto-retry entirely; operator must explicitly retry via /retry-task. Setting to N > 0 re-enables the legacy retry-with-adjustments behavior, capped at N attempts. Glad-Labs/poindexter#370.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('task_sweep_interval_seconds', '300', 'pipeline', 'Seconds between stale task sweeps', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('task_timeout_seconds', '2700', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_alerts_enabled', 'true', 'notifications', 'Telegram is for severity=critical infra alerts only. Discord receives all routine pipeline events (awaiting approval, published, failed). Set 2026-04-24.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_alert_types', 'error,critical,deploy,probe_failure', 'notifications', 'Comma-separated alert types to send (error,critical,deploy,probe_failure,info)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_chat_id', '5318613610', 'notifications', 'Telegram chat ID for all alerts (Matt DM)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_cli_audit_logged', 'true', 'integrations', 'When ''true'' (default), every /cli invocation writes one row to the audit_log table (event_type=''telegram_cli_invoked'' or ''telegram_cli_denied'', source=''telegram_cli''). Captures chat_id, the raw command line, exit code, and duration. Disable only for local-dev noise reduction; leave ''true'' in production so you have a forensic trail of every mobile-issued CLI command.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_cli_enabled', 'true', 'integrations', 'Global kill-switch for the Telegram /cli passthrough. When ''true'' (default), ''/cli <args>'' messages from the configured operator chat are routed to the poindexter CLI and the captured output is replied back. When ''false'', /cli messages are ignored (no reply, no audit row). Use this to disable mobile CLI access without redeploying the bot — for example during a sensitive maintenance window.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_cli_max_output_chars', '3500', 'integrations', 'Maximum characters of combined stdout+stderr the Telegram /cli passthrough will reply with. Telegram''s hard per-message limit is 4096; the default 3500 leaves headroom for the ''exit=N duration=Xs'' header line and a ''[output truncated, N more chars]'' marker. Lower this to keep replies short; raise it (up to ~4000) if you need to see more output and don''t mind the bot occasionally hitting the Telegram cap.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_cli_safe_commands', 'post,settings,validators,auth,check_health,get_post_count,health,version', 'integrations', 'Comma-separated allowlist of top-level poindexter CLI subcommands the Telegram /cli passthrough will execute. The first whitespace-separated token after ''/cli'' must match an entry here, otherwise the bot rejects the command with a ''not on allowlist'' message. Default covers the routine ops set: post show/approve/reject, settings get, validators list/enable/disable, auth list-clients, plus a few read-only health checks. Add more entries here as needed (e.g. ''topics'' once you trust the surface).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('telegram_cli_timeout_seconds', '30', 'integrations', 'Wall-clock timeout (seconds) for a /cli subprocess. After this many seconds the passthrough kills the process group and replies ''command timed out''. Prevents a slow query (or a hung CLI subcommand) from blocking the bot''s Telegram long-poll loop. Default 30s comfortably covers all read-only CLI commands; bump if you find yourself regularly hitting it on legitimate calls.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('template_runner_progress_streaming', 'true', 'pipeline', 'When on, TemplateRunner emits per-node progress to Discord (NOT Telegram) via notify_operator(critical=False). Default true — Discord is the spam channel by design. Telegram is reserved for critical alerts only (worker offline, GPU temp, cost overrun).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('template_runner_use_postgres_checkpointer', 'true', 'pipeline', 'When true, services/template_runner.py compiles each LangGraph with an AsyncPostgresSaver checkpointer (durable state across worker restarts; resumable by thread_id). When false (default), MemorySaver is used — checkpoints live only for the duration of the run. Phase 1.5 of Glad-Labs/poindexter#371; flip to true after operator review of the smoke + fallback tests.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('title_originality_cache_ttl_hours', '24', 'content', 'GH-87: TTL (hours) for the in-process cache that dedupes repeated DuckDuckGo queries for the same title. DDG rate-limits aggressively, so tightening this below 1h is unwise.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('title_originality_external_check_enabled', 'true', 'content', 'GH-87: enable DuckDuckGo HTML search for the exact post title at approval time. Verbatim external matches subtract title_originality_external_penalty from the QA score.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('title_originality_external_penalty', '-50', 'content', 'GH-87: points subtracted from the QA score when the post title appears verbatim in external search results. Stored as a negative integer for human readability; the service code takes the abs value.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_dedup_engine', 'word_overlap', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_dedup_existing_threshold', '0.7', 'pipeline', 'Word-overlap ratio above which a candidate topic is treated as a duplicate of an existing published post or in-flight task (gitea#279). Range 0.0-1.0. Lower = more aggressive filtering. Default 0.7. Was hardcoded 0.4 prior to this fix and was killing 14/14 candidates.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_dedup_intra_batch_threshold', '0.65', 'pipeline', 'Word-overlap ratio above which two candidates from the same scrape batch are treated as duplicates (gitea#279). Range 0.0-1.0. Slightly tighter than vs-existing because a single source dropping near-identical headlines usually IS a dup. Default 0.65.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_auto_enabled', 'false', 'topic_discovery', 'Master kill-switch for the LEGACY auto-firing topic discovery loop in services/idle_worker.py. When ''true'' (default, backward compatible), the loop fires on signals (queue_low, stale_content, rejection_streak) and the 24h safety-net fallback. When ''false'', all auto-firing branches bail out early with an INFO log and no work is queued — operators drive discovery exclusively through the niche-aware operator flow (''poindexter topics rank-batch'' followed by ''poindexter topics resolve-batch''). Manual triggers via topic_discovery_manual_trigger=true still work in either mode so operators can fire one-shot discoveries even with auto disabled. Trade-off: ''true'' keeps the pipeline self-feeding for OSS users with no niches configured, but bypasses the operator approval gate; ''false'' enforces the gate but requires explicit operator action to keep the queue full. See niche-pivot work (#278) and migration 0113 for the operator-driven alternative.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_category_searches', '{}', 'content', 'JSON object mapping category name -> list of keyword search strings. Used by TopicDiscovery._classify_category to bucket a scraped title into a category, and by web-search topic sources to issue DuckDuckGo queries per category. Empty object falls back to the hardcoded Glad Labs categories (technology / startup / security / engineering / insights / business / hardware / gaming) for backwards compatibility. Customers in a different niche should set this to their own category map so classification doesn''t default everything to ''technology''.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_cooldown_minutes', '5', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_ideation_lookback_days', '30', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_length_distribution', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_manual_trigger', 'false', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_min_cooldown_seconds', '1800', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_news_patterns', '[]', 'content', 'JSON array of regex strings (case-insensitive). When non-empty, TopicDiscovery uses these patterns to reject titles as news/junk/merch/etc. instead of the hardcoded Glad Labs set (lawsuit/court, election/senator, shirt/merch, etc.). Empty array falls back to the hardcoded set for backwards compatibility. Customers running Poindexter for a niche where those topics are on-brand (real estate, fashion, politics) should set this to their own array — including ''[]'' to disable regex-based junk filtering entirely. Only the regex-based filter is overridden; the too-short-title guard still applies unconditionally.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_queue_low_threshold', '999', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_rejection_streak', '999', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_stale_hours', '8760', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_streak_window_hours', '6', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('topic_discovery_style_distribution', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('trusted_source_domains', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
