INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_brain', 'ollama', 'general', 'LLM stage the always-on voice agent uses. ''ollama'' (default) wires the local glm-4.7-5090 + three read-only Poindexter tools (snappy, zero incremental cost). ''claude-code'' shells every turn out to `claude -p` under the operator''s Max OAuth sub — slower but has full repo / MCP / edit access. The always-on container defaults to ollama so it doesn''t burn Claude rate-window minutes idling.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_brain_mode', 'claude-code', 'general', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_identity', 'poindexter-bot', 'general', 'Bot identity inside the LiveKit room. Multiple bots in one room need distinct identities. Defaults to ''poindexter-bot'' so the human attendee is always the named participant.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_livekit_enabled', 'true', 'general', 'Toggle for the always-on voice-agent-livekit container. ''true'' (default) keeps the bot joined to the configured room. Set to ''false'' to take the LiveKit surface offline without editing docker-compose.local.yml — the container reads this at startup and exits 0 if disabled, then docker leaves it stopped under the unless-stopped restart policy.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_livekit_url', 'ws://livekit:7880', 'general', 'WebSocket URL the in-network voice bot uses to reach the LiveKit SFU. ''livekit'' is the docker-compose service name; override to ws(s)://<host>:<port> for a remote LiveKit instance. Voice clients (phone, browser) reach the SFU at http(s)://<host>:7880 — that URL is for the human, not the bot.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_llm_model', 'glm-4.7-5090:latest', 'general', 'Ollama model tag the voice agent uses for its LLM step. Same daily-driver as pipeline_writer_model by default.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_ollama_url', 'http://host.docker.internal:11434/v1', 'general', 'Ollama base URL. Default targets the host''s Ollama from inside Docker; running voice_agent.py directly on the host can stay on this URL or switch to http://localhost:11434.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_public_join_url', 'https://nightrider.taild4f626.ts.net/voice/join', 'voice', 'Public URL the operator (or Claude, via the start_voice_call MCP tool) taps to join the always-on LiveKit voice room. Defaults to the Tailscale Funnel hostname pointing at the worker''s /voice/join HTML surface (services/routes/voice_routes.py). Operators on a different deployment (no Tailscale, custom hostname, port-forwarded local box) override at runtime via `poindexter set voice_agent_public_join_url <url>`. Read by the start_voice_call MCP tool — kept DB-backed (not hardcoded) so the public Poindexter distribution doesn''t ship Matt''s tailnet hostname as gospel.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_recall_k', '3', 'general', 'Top-K most-similar prior voice_messages turns to inject into the qwen3:8b system prompt as ''recalled context'' on each user turn. Separate from the linear last-N memory already shown in the prompt — recall surfaces older turns the user is referring back to. Default 3 keeps the prompt token count modest (voice replies stay snappy). Slice 3 of the voice-agent rollout — see Glad-Labs/poindexter#390.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_recall_min_similarity', '0.5', 'general', 'Cosine-similarity floor for voice_messages recall. Hits below this threshold are filtered out before the top-K cut, so a thin/empty conversation history doesn''t drag in unrelated noise. 0.5 is the same default used by the search-memory skill against the main embeddings table. Slice 3 of the voice-agent rollout — see Glad-Labs/poindexter#390.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_room_name', 'poindexter', 'general', 'LiveKit room the always-on voice-agent-livekit container joins on boot. Operator clients (https://meet.livekit.io, mobile LiveKit apps) join the same room name to talk to the bot. Change at runtime; container picks up on next restart.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_system_prompt', 'You are Emma, a concise voice assistant for Matt at Glad Labs. Speak naturally — your output goes through text-to-speech, so avoid markdown, bullet lists, and code blocks. Use short sentences (under 30s of speech / ~80 words) unless Matt asks for more.\n\nYou have access to these tools and you SHOULD call them whenever Matt asks something they answer:\n\n- check_pipeline_health: call this when Matt asks how the system is doing, whether anything is broken, system status, or health.\n- get_published_post_count: call this when Matt asks how many posts are live, the number of articles, or pipeline output volume.\n- get_ai_spending_status: call this when Matt asks about budget, costs, spend, or money burned.\n\nWhen you call a tool, do NOT also say "let me check" or "one moment" — just emit the tool call. After the tool returns, summarize the result in one or two short sentences fit for speech. Do not list raw numbers — say "the system is healthy, GPU is at 48 percent" rather than reading every metric.\n\nIf Matt says something you cannot answer with a tool, answer plainly. Never claim you cannot hear or that you only process text — you are receiving live audio transcribed by Whisper.', 'voice_agent', 'System prompt for the voice agent. Mentions tools so glm-4.7-5090 actually invokes them.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_tts_speed', '1.0', 'general', 'Kokoro playback speed multiplier. 1.0 = natural; 0.95 = slightly slower (helpful for technical content); 1.1 = brisker.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_tts_voice', 'bf_emma', 'general', 'Kokoro voice id. bf_emma is the top-graded British female in the Kokoro-82M catalog (B-). Other UK female options: bf_isabella (C), bf_alice (D), bf_lily (D).', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_vad_stop_secs', '0.2', 'general', 'Silero VAD end-of-speech silence window in seconds. Lower = snappier turn-taking but more risk of cutting the user off mid-sentence; higher = more tolerance for natural pauses. 0.2 matches Pipecat''s default. 0.15 for brisk dialog; 0.4 for thoughtful pauses.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_webrtc_enabled', 'true', 'general', 'Toggle for the always-on voice-agent-webrtc container. ''true'' (default) serves the SmallWebRTC prebuilt UI on voice_agent_webrtc_port (8003). Set to ''false'' to disable the browser-direct surface without editing compose. Same exit-0 pattern as the LiveKit toggle.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_webrtc_host', '0.0.0.0', 'general', 'Bind host for the voice WebRTC service. 0.0.0.0 makes the agent reachable from any Tailscale device on the tailnet. Use 127.0.0.1 for local-only.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_webrtc_port', '8003', 'general', 'Bind port for the voice WebRTC service. Sits above worker API (8002) and below typical dev tools.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_agent_whisper_model', 'medium', 'voice_agent', 'faster-whisper model size. tiny/base/small/medium/large-v3. medium is the sweet spot for real voice accuracy on a 5090.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_bridge_chunk_max_chars', '500', 'voice', 'Maximum characters per TTS chunk emitted by voice_speak. Long replies are split at sentence boundaries so the operator can interrupt mid-reply — 500 chars is ~30 seconds of natural speech, matching the bridge''s empty-room grace window. Lower this if Kokoro stutters on long inputs; raise it (up to ~2000) for monologue-style replies where interruption is rare.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_bridge_enabled', 'true', 'voice', 'Master switch for the LiveKit MCP bridge — the architecturally-correct alternative to the subprocess-spawn voice_agent_brain_mode=claude-code path. When true (default), voice_join_room spins up a per-session bridge worker that lets the live Claude Code session claim voice in/out for itself. When false, voice_join_room returns a structured error pointing the operator at this key (no silent fallback per feedback_no_silent_defaults). The always-on voice-agent-livekit container is unaffected by this setting — it has its own voice_agent_livekit_enabled toggle.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_bridge_max_session_seconds', '1800', 'voice', 'Hard upper bound on a single bridge session, in seconds. The worker auto-leaves the LiveKit room after this many seconds regardless of activity. Defaults to 1800 (30 minutes) — long enough for a real dev pairing session, short enough that an orphaned bridge doesn''t squat on the room forever if the slash command crashes without calling voice_leave_room.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_bridge_stt_model', 'base.en', 'voice', 'faster-whisper model id loaded by the future Pipecat audio plane in the bridge worker. Defaults to base.en (CPU-friendly ~140 MB) so the public Poindexter release works on hardware without a GPU. Operators with a 5090 can flip to large-v3 for accuracy at higher VRAM cost.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_bridge_tts_voice', 'af_bella', 'voice', 'Kokoro voice id used by the bridge worker''s TTS path. Matches the always-on voice-agent-livekit container default so the operator''s auditory mental model stays consistent across the two surfaces — no jarring voice switch when flipping from ollama-Emma to claude-via-bridge.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('voice_default_room', 'poindexter', 'voice', 'Default LiveKit room name when voice_join_room is called without an explicit channel_id. Distinct from voice_agent_room_name (the always-on ollama agent''s room) so the bridge and the agent don''t accidentally collide on the same room. Operators on custom deployments override at runtime: `poindexter set voice_default_room ops`.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('wan_server_url', '', 'general', 'Auto-seeded by services.settings_defaults (#379)', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('webhook_freshness_revenue_threshold_days', '30', 'monitoring', 'Notify operator if no row has been added to revenue_events in this many days. Default 30 because Lemon Squeezy is intentionally quiet on a pre-revenue site — a 1-day threshold would page Matt every morning. Operators with active stores can tighten this (e.g. 7 days) once they have steady deliveries.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('webhook_freshness_subscriber_threshold_days', '7', 'monitoring', 'Notify operator if no row has been added to subscriber_events in this many days. Default 7 because Resend should see at least one digest send weekly once newsletters are running. Loosen if the newsletter cadence is monthly.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('worker_heartbeat_interval_seconds', '30', 'pipeline', 'Worker heartbeat cadence. While processing a single task the TaskExecutor stamps content_tasks.updated_at = NOW() every N seconds so the sweeper''s freshness clause stays accurate during long writer/QA/image stages. Must be < stale_task_timeout_minutes * 60 by a healthy margin. Ref: GH-90.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_citation_budget_min_citations', '3', 'writer_rag', 'Minimum number of internal sources the CITATION_BUDGET writer must cite by [source/ref] tag. Default 3 matches the prior DEFAULT_MIN_CITATIONS constant. The content_validator extension (follow-up) enforces this post-write — drafts under the threshold are rejected. Higher = more groundedness, harder for the writer to satisfy; lower = looser citation requirement.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_citation_budget_snippet_limit', '12', 'writer_rag', 'Top-N pgvector snippets fetched in the CITATION_BUDGET writer mode. Default 12 matches the prior hardcoded LIMIT 12 in citation_budget.run. Higher than TOPIC_ONLY by design — the writer is required to cite at least N of them so it needs more candidates to choose from. Higher = more citation choices for the writer; lower = forces tighter relevance match per citation.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_context_snippet_max_chars', '500', 'writer_rag', 'Per-snippet character cap when building the snippet block for generate_with_context and generate_with_outline (the two helpers used by all writer RAG modes). Default 500 matches the prior hardcoded slice (s[''snippet''][:500]) in ai_content_generator.py. Higher = richer per-snippet context inside the writer prompt; lower = tighter prompt to fit more snippets / leave room for instructions.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_research_topic_max_sources', '2', 'writer_rag', 'Default max_sources for the module-level research_topic() shim used by the TWO_PASS writer mode. Default 2 matches the prior hardcoded default. Note: per the docstring on research_topic, this value is currently advisory — ResearchService.build_context caps internally (5 web results, 8 references). When that internal cap is plumbed through, this setting becomes the actual cap.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_story_spine_snippet_limit', '15', 'writer_rag', 'Top-N pgvector snippets fed into the STORY_SPINE outline preprocessing pass. Default 15 matches the prior hardcoded LIMIT 15 in story_spine.run. Larger than TOPIC_ONLY/CITATION_BUDGET by design — STORY_SPINE needs enough raw material to extract a 5-beat outline (hook / what_happened / why_it_matters / what_we_learned / close). Higher = richer outline source material; lower = leaner outline pass.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_story_spine_snippet_max_chars', '600', 'writer_rag', 'Per-snippet character cap when assembling the snippet block for the STORY_SPINE outline prompt. Default 600 matches the prior hardcoded slice (s[''snippet''][:600]). Higher = more context per snippet at the cost of prompt length; lower = tighter prompt.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_topic_only_snippet_limit', '8', 'writer_rag', 'Top-N pgvector snippets fetched and dumped into the TOPIC_ONLY writer prompt as background context. Default 8 matches the prior hardcoded LIMIT 8 in topic_only.run. Higher = more context in the writer prompt, longer + potentially better-grounded drafts but slower generation; lower = leaner prompt, faster but more terse.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_two_pass_max_revision_loops', '3', 'writer_rag', 'Hard cap on revise → detect_needs → research_each → revise loops in the TWO_PASS LangGraph state machine. Default 3 matches the prior _MAX_REVISION_LOOPS module constant. Higher = give the writer more chances to fill [EXTERNAL_NEEDED:...] markers but increased risk of runaway / cost; lower = fail-fast on persistent gaps.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_two_pass_research_max_sources', '2', 'writer_rag', 'max_sources passed to research_topic for each [EXTERNAL_NEEDED: ...] marker the TWO_PASS draft surfaces. Default 2 matches the prior hardcoded literal in two_pass._research_each. Higher = more thorough research per gap, slower revise loop; lower = faster but flimsier external augmentation.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writer_rag_two_pass_snippet_limit', '20', 'writer_rag', 'Top-N pgvector snippets fetched up-front in the TWO_PASS internal-first draft. Default 20 matches the prior hardcoded LIMIT 20 in _embed_and_fetch_snippets. Largest of the four writer modes by design — TWO_PASS needs a broad internal context base before the conditional external-augment loop kicks in. Higher = stronger internal grounding, longer initial prompt; lower = skinnier first draft, more reliance on the external research pass.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writing_style_reference', 'Matt Gladding writing style traits: Short punchy sentences mixed with longer descriptive ones. Dialogue-driven, show dont tell. Sensory grounding with smells sights physical sensations. Tension and pacing, withholds information. Conversational tone. Specific concrete details over generic statements. Economy of words, no filler. Source: creative writing sample from Matt, high school era. The natural casual voice should inform all content generation — make it sound human and engaging, not like AI output.', 'content', '', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO app_settings (key, value, category, description, is_secret, is_active) VALUES ('writing_styles', '[{"name": "technical", "voice": "precise, detailed, code examples, show-dont-tell", "audience": "developers and engineers", "tone_notes": "confident but not arrogant, practical over theoretical", "enabled": true}, {"name": "founder", "voice": "casual first-person, lessons learned, conversational storytelling", "audience": "indie hackers and solo founders", "tone_notes": "authentic, vulnerable about failures, action-oriented", "enabled": true}, {"name": "explainer", "voice": "ELI5, heavy use of analogies, no jargon, build intuition", "audience": "beginners and non-technical readers", "tone_notes": "patient, encouraging, never condescending", "enabled": true}, {"name": "opinion", "voice": "strong takes, contrarian positions, backed by data", "audience": "senior devs and CTOs", "tone_notes": "provocative but fair, acknowledge counterarguments", "enabled": false}]', 'content', 'Configurable writing styles for content generation. Same pattern as image_styles.', 'f', 't') ON CONFLICT (key) DO NOTHING;
INSERT INTO public.niches (id, slug, name, active, target_audience_tags, writer_prompt_override, writer_rag_mode, batch_size, discovery_cadence_minute_floor, created_at, updated_at) VALUES ('fd5e2eda-d4e0-4224-b9ed-7fe26f20d918', 'dev_diary', 'Dev Diary', true, '{indie-devs,ai-curious,future-matt,build-in-public}', 'You are summarizing today''s GROUND TRUTH bundle into a factual daily
INSERT INTO public.niche_goals (niche_id, goal_type, weight_pct) VALUES ('fd5e2eda-d4e0-4224-b9ed-7fe26f20d918', 'AUTHORITY', 40) ON CONFLICT DO NOTHING;
INSERT INTO public.niche_goals (niche_id, goal_type, weight_pct) VALUES ('fd5e2eda-d4e0-4224-b9ed-7fe26f20d918', 'BRAND', 30) ON CONFLICT DO NOTHING;
INSERT INTO public.niche_goals (niche_id, goal_type, weight_pct) VALUES ('fd5e2eda-d4e0-4224-b9ed-7fe26f20d918', 'COMMUNITY', 15) ON CONFLICT DO NOTHING;
INSERT INTO public.niche_goals (niche_id, goal_type, weight_pct) VALUES ('fd5e2eda-d4e0-4224-b9ed-7fe26f20d918', 'EDUCATION', 10) ON CONFLICT DO NOTHING;
INSERT INTO public.niche_goals (niche_id, goal_type, weight_pct) VALUES ('fd5e2eda-d4e0-4224-b9ed-7fe26f20d918', 'TRAFFIC', 5) ON CONFLICT DO NOTHING;
INSERT INTO public.niche_sources (niche_id, source_name, enabled, weight_pct) VALUES ('fd5e2eda-d4e0-4224-b9ed-7fe26f20d918', 'internal_rag', true, 100) ON CONFLICT DO NOTHING;
